import React, { useEffect, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { baiDangAPI, yeuCauAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './ChiTietBaiDang.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n);

export default function ChiTietBaiDang() {
  const { id } = useParams();
  const { user } = useAuthStore();
  const navigate = useNavigate();
  const [bd, setBd] = useState(null);
  const [loading, setLoading] = useState(true);
  const [applying, setApplying] = useState(false);
  const [moTaYeuCau, setMoTaYeuCau] = useState('');
  const [showApply, setShowApply] = useState(false);
  const [imgIdx, setImgIdx] = useState(0);

  useEffect(() => {
    baiDangAPI.layChiTiet(id)
      .then(response => setBd(response.data.data))
      .catch(() => toast.error('Khong tim thay bai dang'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleApply = async () => {
    if (!user) {
      navigate('/dang-nhap');
      return;
    }

    if (!user.xacThuc) {
      toast.error('Ban can xac thuc CCCD truoc khi apply');
      navigate('/xac-thuc');
      return;
    }

    setApplying(true);
    try {
      await yeuCauAPI.gui({ maPhong: bd.maPhong, moTa: moTaYeuCau });
      toast.success('Da gui yeu cau tham gia');
      setShowApply(false);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Gui yeu cau that bai');
    } finally {
      setApplying(false);
    }
  };

  if (loading) return <div className="spinner" />;
  if (!bd) {
    return (
      <div className="container page-wrapper">
        <div className="alert alert-danger">Khong tim thay bai dang.</div>
      </div>
    );
  }

  const imgs = bd.images || [];

  return (
    <div className="container page-wrapper">
      <div className="chitiet-layout">
        <div>
          <div className="gallery">
            <div className="gallery-main">
              {imgs.length > 0 ? (
                <img src={imgs[imgIdx]} alt="Phong" />
              ) : (
                <div className="gallery-placeholder">Nha</div>
              )}
            </div>

            {imgs.length > 1 && (
              <div className="gallery-thumbs">
                {imgs.map((img, index) => (
                  <img
                    key={img}
                    src={img}
                    alt=""
                    className={index === imgIdx ? 'active' : ''}
                    onClick={() => setImgIdx(index)}
                  />
                ))}
              </div>
            )}
          </div>

          <div className="card" style={{ marginTop: 24 }}>
            <div className="card-body">
              <h1 className="chitiet-title">{bd.moTa}</h1>
              <div className="chitiet-price">{fmt(bd.giaTien)}/thang</div>
              <div className="chitiet-address">Dia chi: {bd.diaChi}</div>

              {bd.noiDung && (
                <div className="chitiet-content">
                  <h3>Mo ta chi tiet</h3>
                  <p>{bd.noiDung}</p>
                </div>
              )}

              {bd.maPhong && (
                <div className="chitiet-phong-info">
                  <h3>Thong tin phong</h3>
                  <p>Ma phong: #{bd.maPhong}</p>
                </div>
              )}
            </div>
          </div>
        </div>

        <div>
          <div className="card poster-card">
            <div className="card-body">
              <h3 style={{ marginBottom: 16 }}>Nguoi dang</h3>

              <Link to={`/nguoi-dung/${bd.maNguoiDang}`} className="poster-info" style={{ textDecoration: 'none' }}>
                <img
                  src={bd.avatarNguoiDang || `https://ui-avatars.com/api/?name=${encodeURIComponent(bd.tenNguoiDang || 'U')}&background=12355B&color=fff&size=60`}
                  className="avatar avatar-lg"
                  alt={bd.tenNguoiDang || 'Nguoi dang'}
                />
                <div>
                  <div style={{ fontWeight: 700, fontSize: 18 }}>{bd.tenNguoiDang}</div>
                  <div style={{ marginTop: 6, fontSize: 13, color: 'var(--text-muted)' }}>
                    Bam vao avatar hoac ten de xem ho so cong khai
                  </div>
                </div>
              </Link>

              <Link
                to={`/nguoi-dung/${bd.maNguoiDang}`}
                className="btn btn-outline btn-block"
                style={{ marginTop: 14 }}
              >
                Xem ho so nguoi dang
              </Link>

              <div style={{ marginTop: 20 }}>
                <div className="info-row"><span>Luot xem</span><strong>{bd.soLuotXem}</strong></div>
                <div className="info-row"><span>Ngay dang</span><strong>{bd.ngayDang ? new Date(bd.ngayDang).toLocaleDateString('vi-VN') : ''}</strong></div>
                <div className="info-row">
                  <span>Trang thai</span>
                  <span className={`badge ${bd.trangThai === 'Dang' ? 'badge-success' : 'badge-gray'}`}>
                    {bd.trangThai === 'Dang' ? 'Dang dang' : bd.trangThai}
                  </span>
                </div>
              </div>

              {user?.maNguoiDung !== bd.maNguoiDang && bd.maPhong && (
                <div style={{ marginTop: 20 }}>
                  {!showApply ? (
                    <button className="btn btn-primary btn-block btn-lg" onClick={() => setShowApply(true)}>
                      Apply vao phong nay
                    </button>
                  ) : (
                    <div>
                      <textarea
                        className="form-control"
                        rows={3}
                        placeholder="Gioi thieu ban than..."
                        value={moTaYeuCau}
                        onChange={event => setMoTaYeuCau(event.target.value)}
                        style={{ marginBottom: 10 }}
                      />
                      <div style={{ display: 'flex', gap: 8 }}>
                        <button className="btn btn-primary" style={{ flex: 1 }} onClick={handleApply} disabled={applying}>
                          {applying ? 'Dang gui...' : 'Gui yeu cau'}
                        </button>
                        <button className="btn btn-secondary" onClick={() => setShowApply(false)}>Huy</button>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
